local _p = ""
local _k = 249
local _b = bit32 or bit
local _bx = (_b and _b.bxor) or function(a,b)
    local r, p = 0, 1
    while a>0 and b>0 do
        local ra, rb = a%2, b%2
        if ra~=rb then r=r+p end
        a,b,p = (a-ra)/2,(b-rb)/2,p*2
    end
    if a<b then a=b end
    while a>0 do
        local ra = a%2
        if ra>0 then r=r+p end
        a,p = (a-ra)/2,p*2
    end
    return r
end
local _char = string.char
local _sub = string.sub
local _b64 = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/"
local _d64 = {}
for i=1, 64 do _d64[_b64:sub(i,i)] = i-1 end
local function _dec(d)
    d = d:gsub("[^" .. _b64 .. "=]", "")
    local res = {}
    local t, b = 0, 0
    for i=1, #d do
        local c = d:sub(i,i)
        if c == "=" then break end
        t = t * 64 + _d64[c]
        b = b + 6
        if b >= 8 then
            b = b - 8
            res[#res+1] = _char(math.floor(t / (2^b)) % 256)
            t = t % (2^b)
        end
    end
    return table.concat(res)
end
local _enc = _dec(_p)
local _o = {}
for i=1, #_enc do
    local nb = _enc:sub(i,i):byte()
    _o[i] = _char(_bx(nb, _k))
    _k = (_k + nb) % 256
end
local _src = _dec(table.concat(_o))
local _f, _e = (loadstring or load)(_src)
if _f then 
    local _s, _err = pcall(_f)
    if not _s then warn("[ALCATRAS] Runtime Error: " .. tostring(_err)) end
else 
    warn("[ALCATRAS] Loader Error: " .. tostring(_e))
end
